var e=[{id:`L2_1`,type:`dialog`,speaker:`RABBIT_YAKSHA_NULL_NULL`,text:{KOREA:`최선의 선택이라는 게 항상 옳다고 생각할 만큼… 그렇게 순진하진 않아.`,JPN:`最善の選択がつねに正しいと思うほど……そんなに無垢じゃない。`,ENG:`I'm not so naive... to believe that the best choice is always the right one.`,TWN:`我沒有天真到認為最好的選擇總是正確的…`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RABBIT_YAKSHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RABBIT_YAKSHA_NULL_NULL`,text:{KOREA:`우리 동포는 나름의 방식대로 세계를 지켜나가겠어. 그게 그 아이가 우리에게 남긴 의지니까.`,JPN:`私たちの仲間はそれなりのやり方で世界を守っている。それがあの子が私たちに残した想いだから。`,ENG:`My compatriots and I will protect the world our own way. That's the will that she left to us.`,TWN:`我們的同伴會用自己的方式來保護這個世界。因為那是她留給我們的意志。我並不天真到認為最好的選擇總是正確的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RABBIT_YAKSHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};